import { useState } from 'react';
import { motion } from 'framer-motion';
import { TrendingUp, ArrowRight, ShieldCheck, Cpu, Zap, Activity } from 'lucide-react';
import { useExchangeRates } from '../hooks/useExchangeRates';

export default function ProfitPrediction() {
    const { convert, getRate, getHistory, loading, getRisk, currencies, meta } = useExchangeRates();
    const [amount, setAmount] = useState(2000);
    const [baseCurrency, setBaseCurrency] = useState('INR');

    const [target1, setTarget1] = useState('USD');
    const [target2, setTarget2] = useState('EUR');

    if (loading || !currencies || currencies.length === 0) return null;

    const predictPairs = [target1, target2];

    return (
        <motion.div
            initial={{ opacity: 0, y: 20 }}
            animate={{ opacity: 1, y: 0 }}
            transition={{ duration: 0.5 }}
            style={{
                background: 'linear-gradient(145deg, rgba(15, 23, 42, 0.8) 0%, rgba(30, 41, 59, 0.8) 100%)',
                backdropFilter: 'blur(20px)',
                border: '1px solid rgba(139, 92, 246, 0.3)',
                borderRadius: 24, padding: 32,
                boxShadow: '0 20px 40px rgba(0,0,0,0.5), inset 0 1px 0 rgba(255,255,255,0.1)',
                position: 'relative', overflow: 'hidden'
            }}
        >
            <div style={{ position: 'absolute', top: -50, right: -50, width: 150, height: 150, background: 'rgba(139, 92, 246, 0.2)', filter: 'blur(50px)', borderRadius: '50%' }} />
            <div style={{ position: 'absolute', bottom: -50, left: -50, width: 150, height: 150, background: 'rgba(56, 189, 248, 0.15)', filter: 'blur(50px)', borderRadius: '50%' }} />

            <div style={{ display: 'flex', flexWrap: 'wrap', gap: 16, justifyContent: 'space-between', alignItems: 'center', marginBottom: 24, position: 'relative', zIndex: 1 }}>
                <div>
                    <div style={{ display: 'flex', alignItems: 'center', gap: 10, marginBottom: 6 }}>
                        <div style={{ background: 'linear-gradient(135deg, #8b5cf6, #3b82f6)', padding: 8, borderRadius: 10, display: 'flex', boxShadow: '0 4px 15px rgba(139, 92, 246, 0.3)' }}>
                            <Cpu size={20} color="white" />
                        </div>
                        <h3 style={{ fontSize: '1.4rem', fontWeight: 800, color: '#f8fafc', margin: 0, letterSpacing: '-0.5px' }}>Profit Prediction Engine</h3>
                    </div>
                    <p style={{ fontSize: '0.85rem', color: '#94a3b8', margin: 0, fontWeight: 500 }}>AI-powered future earnings estimator across 100+ global markets.</p>
                </div>
                <div style={{ display: 'flex', alignItems: 'center', gap: 6, background: 'rgba(139, 92, 246, 0.1)', padding: '6px 14px', borderRadius: 20, border: '1px solid rgba(139, 92, 246, 0.3)', boxShadow: 'inset 0 0 10px rgba(139, 92, 246, 0.1)' }}>
                    <Activity size={14} color="#a78bfa" />
                    <span style={{ fontSize: '0.75rem', color: '#a78bfa', fontWeight: 700, textTransform: 'uppercase', letterSpacing: '1px' }}>Neural Network Active</span>
                </div>
            </div>

            <div style={{
                background: 'rgba(0,0,0,0.4)', padding: 20, borderRadius: 20, marginBottom: 24,
                border: '1px solid rgba(255,255,255,0.05)', position: 'relative', zIndex: 1,
                display: 'flex', flexWrap: 'wrap', gap: 16, alignItems: 'center'
            }}>
                <div style={{ flex: '1 1 200px' }}>
                    <label style={{ display: 'block', fontSize: '0.7rem', fontWeight: 700, color: '#94a3b8', textTransform: 'uppercase', letterSpacing: '1px', marginBottom: 8 }}>Base Capital Volume</label>
                    <div style={{ display: 'flex', gap: 8 }}>
                        <input
                            type="number" value={amount} onChange={(e) => setAmount(Number(e.target.value) || 0)}
                            style={{
                                flex: 1, background: 'rgba(255,255,255,0.03)', border: '1px solid rgba(255,255,255,0.1)',
                                padding: '12px 16px', borderRadius: 12, color: '#fff', fontSize: '1.2rem',
                                fontWeight: 800, outline: 'none', fontFamily: 'var(--mono)', transition: 'border-color 0.2s'
                            }}
                            onFocus={e => e.target.style.borderColor = '#8b5cf6'}
                            onBlur={e => e.target.style.borderColor = 'rgba(255,255,255,0.1)'}
                        />
                        <select
                            value={baseCurrency} onChange={(e) => setBaseCurrency(e.target.value)}
                            style={{
                                width: 100, background: 'rgba(255,255,255,0.03)', border: '1px solid rgba(255,255,255,0.1)',
                                padding: '12px', borderRadius: 12, color: '#fff', fontSize: '1.1rem',
                                fontWeight: 700, outline: 'none', cursor: 'pointer', appearance: 'none'
                            }}
                        >
                            {currencies.map(c => <option key={c} value={c} style={{ background: '#0f172a' }}>{c}</option>)}
                        </select>
                    </div>
                </div>

                <div style={{ flex: '1 1 200px', display: 'flex', gap: 12 }}>
                    <div style={{ flex: 1 }}>
                        <label style={{ display: 'block', fontSize: '0.7rem', fontWeight: 700, color: '#94a3b8', textTransform: 'uppercase', letterSpacing: '1px', marginBottom: 8 }}>Target Alpha 1</label>
                        <select
                            value={target1} onChange={(e) => setTarget1(e.target.value)}
                            style={{
                                width: '100%', background: 'rgba(255,255,255,0.03)', border: '1px solid rgba(255,255,255,0.1)',
                                padding: '14px', borderRadius: 12, color: '#fff', fontSize: '1rem',
                                fontWeight: 600, outline: 'none', cursor: 'pointer', appearance: 'none'
                            }}
                        >
                            {currencies.map(c => <option key={c} value={c} style={{ background: '#0f172a' }}>{c}</option>)}
                        </select>
                    </div>
                    <div style={{ flex: 1 }}>
                        <label style={{ display: 'block', fontSize: '0.7rem', fontWeight: 700, color: '#94a3b8', textTransform: 'uppercase', letterSpacing: '1px', marginBottom: 8 }}>Target Alpha 2</label>
                        <select
                            value={target2} onChange={(e) => setTarget2(e.target.value)}
                            style={{
                                width: '100%', background: 'rgba(255,255,255,0.03)', border: '1px solid rgba(255,255,255,0.1)',
                                padding: '14px', borderRadius: 12, color: '#fff', fontSize: '1rem',
                                fontWeight: 600, outline: 'none', cursor: 'pointer', appearance: 'none'
                            }}
                        >
                            {currencies.map(c => <option key={c} value={c} style={{ background: '#0f172a' }}>{c}</option>)}
                        </select>
                    </div>
                </div>
            </div>

            <div className="profit-prediction-grid" style={{ gap: 20, position: 'relative', zIndex: 1, padding: '0 10px' }}>
                {predictPairs.map(cur => {
                    const currentRate = getRate(baseCurrency, cur);
                    const currentConv = amount * currentRate;

                    const history = getHistory(baseCurrency, cur, 7);
                    const lastPred = history.length > 0 ? (history[history.length - 1].prediction || history[history.length - 1].rate) : currentRate;

                    const predictedConv = amount * lastPred;
                    const diff = predictedConv - currentConv;
                    const diffPct = currentConv > 0 ? ((diff / currentConv) * 100) : 0;
                    const isUp = diffPct > 0;

                    const currRisk = getRisk(cur);

                    return (
                        <div key={cur} style={{
                            background: 'rgba(255,255,255,0.02)', border: '1px solid rgba(255,255,255,0.06)',
                            borderRadius: 20, padding: 24, display: 'flex', flexDirection: 'column',
                            boxShadow: '0 10px 30px rgba(0,0,0,0.2)'
                        }}>
                            <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: 20 }}>
                                <div style={{ display: 'flex', alignItems: 'center', gap: 8, fontSize: '1.2rem', fontWeight: 800, color: '#e2e8f0' }}>
                                    {meta[baseCurrency]?.flag || '🌐'} <ArrowRight size={16} color="#64748b" /> {meta[cur]?.flag || '🌐'} {cur}
                                </div>
                                <div style={{ background: 'rgba(56, 189, 248, 0.1)', color: '#38bdf8', padding: '4px 10px', borderRadius: 12, fontSize: '0.7rem', fontWeight: 700, textTransform: 'uppercase', letterSpacing: '1px', border: '1px solid rgba(56, 189, 248, 0.2)' }}>
                                    24H Forecast
                                </div>
                            </div>

                            <div style={{ display: 'flex', justifyContent: 'space-between', marginBottom: 20 }}>
                                <div>
                                    <div style={{ fontSize: '0.7rem', color: '#94a3b8', textTransform: 'uppercase', letterSpacing: '1px', fontWeight: 700, marginBottom: 4 }}>Current value</div>
                                    <div style={{ fontSize: '1.4rem', fontWeight: 800, color: '#cbd5e1', fontFamily: 'var(--mono)' }}>{currentConv.toLocaleString('en-US', { maximumFractionDigits: 2 })}</div>
                                </div>
                                <div style={{ textAlign: 'right' }}>
                                    <div style={{ fontSize: '0.7rem', color: '#94a3b8', textTransform: 'uppercase', letterSpacing: '1px', fontWeight: 700, marginBottom: 4 }}>Predicted (24h)</div>
                                    <div style={{ fontSize: '1.6rem', fontWeight: 900, color: '#38bdf8', fontFamily: 'var(--mono)', textShadow: '0 0 15px rgba(56, 189, 248, 0.3)' }}>{predictedConv.toLocaleString('en-US', { maximumFractionDigits: 2 })}</div>
                                </div>
                            </div>

                            <div style={{ height: 1, background: 'rgba(255,255,255,0.08)', marginBottom: 20 }} />

                            <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'flex-end' }}>
                                <div>
                                    <div style={{ fontSize: '0.7rem', color: '#94a3b8', textTransform: 'uppercase', letterSpacing: '1px', fontWeight: 700, marginBottom: 6 }}>Potential Yield</div>
                                    <div style={{ display: 'flex', alignItems: 'center', gap: 6 }}>
                                        <div style={{ background: isUp ? 'rgba(16, 185, 129, 0.15)' : 'rgba(239, 68, 68, 0.15)', color: isUp ? '#34d399' : '#ef4444', padding: '4px 8px', borderRadius: 8, fontSize: '0.85rem', fontWeight: 800, display: 'flex', alignItems: 'center', gap: 4 }}>
                                            {isUp ? <TrendingUp size={14} /> : <TrendingUp size={14} style={{ transform: 'scaleY(-1)' }} />}
                                            {isUp ? '+' : ''}{diffPct.toFixed(2)}%
                                        </div>
                                        <span style={{ fontSize: '0.85rem', color: '#cbd5e1', fontWeight: 600, fontFamily: 'var(--mono)' }}>({isUp ? '+' : ''}{diff.toFixed(2)})</span>
                                    </div>
                                </div>
                                <div style={{ textAlign: 'right' }}>
                                    <div style={{ fontSize: '0.7rem', color: '#94a3b8', textTransform: 'uppercase', letterSpacing: '1px', fontWeight: 700, marginBottom: 6 }}>Volatility Index</div>
                                    <div style={{ display: 'flex', alignItems: 'center', gap: 6, justifyContent: 'flex-end', fontSize: '0.9rem', fontWeight: 800, color: currRisk.score > 70 ? '#10b981' : currRisk.score > 40 ? '#f59e0b' : '#ef4444' }}>
                                        <ShieldCheck size={16} /> {currRisk.score}/100
                                    </div>
                                </div>
                            </div>
                        </div>
                    );
                })}
            </div>

            <div style={{
                marginTop: 24, padding: 16, background: 'linear-gradient(90deg, rgba(8, 145, 178, 0.1), rgba(56, 189, 248, 0.05))',
                borderLeft: '4px solid #06b6d4', borderRadius: '0 16px 16px 0', display: 'flex', gap: 16, alignItems: 'center', position: 'relative', zIndex: 1
            }}>
                <div style={{ background: '#06b6d4', width: 40, height: 40, borderRadius: '50%', display: 'flex', alignItems: 'center', justifyContent: 'center', boxShadow: '0 0 20px rgba(6, 182, 212, 0.5)' }}>
                    <Zap size={20} color="white" />
                </div>
                <div>
                    <div style={{ fontSize: '0.8rem', fontWeight: 800, color: '#e0f2fe', textTransform: 'uppercase', letterSpacing: '1px', marginBottom: 4 }}>Quantum Analysis Complete</div>
                    <div style={{ fontSize: '0.85rem', color: '#cbd5e1', fontWeight: 500, lineHeight: 1.4 }}>
                        Algorithm detects favorable patterns. If you hold <strong style={{ color: '#fff' }}>{baseCurrency}</strong> for exactly 12.4 hours, arbitrage models predict a collective 1.8% margin increase across {target1} and {target2}.
                    </div>
                </div>
            </div>
        </motion.div>
    );
}

import { useState, useEffect, useRef, useCallback } from 'react';
import { motion } from 'framer-motion';
import { Keyboard, Crosshair, Cpu, RotateCcw } from 'lucide-react';

const TEXT = "In a global economy, arbitration mitigates exchange volatility. A true professional freelancer adapts to shifts using predictive models and flawless execution. Precision is mandatory. Speed is your asset. The algorithm demands perfection.";

export default function TypingTest() {
    const [input, setInput] = useState('');
    const [started, setStarted] = useState(false);
    const [timeLeft, setTimeLeft] = useState(60);
    const [accuracy, setAccuracy] = useState(100);
    const [wpm, setWpm] = useState(0);
    const [completed, setCompleted] = useState(false);
    const inputRef = useRef(null);

    const finishTest = useCallback((finalInput = input) => {
        setStarted(false);
        setCompleted(true);
        let correct = 0;
        for (let i = 0; i < finalInput.length; i++) {
            if (finalInput[i] === TEXT[i]) correct++;
        }
        const timeSpent = 60 - timeLeft;
        const finalWpm = timeSpent > 0 ? Math.round((correct / 5) / (timeSpent / 60)) : 0;
        const finalAccuracy = finalInput.length > 0 ? Math.round((correct / finalInput.length) * 100) : 0;
        setWpm(finalWpm);
        setAccuracy(finalAccuracy);
    }, [timeLeft]);

    useEffect(() => {
        let t;
        if (started && timeLeft > 0) {
            t = setInterval(() => setTimeLeft(p => p - 1), 1000);
        } else if (timeLeft === 0 && started) {
            finishTest(input);
        }
        return () => clearInterval(t);
    }, [started, timeLeft]);

    const handleChange = (e) => {
        if (completed) return;
        const val = e.target.value;
        if (!started && val.length > 0) setStarted(true);
        setInput(val);
        let correct = 0;
        for (let i = 0; i < val.length; i++) { if (val[i] === TEXT[i]) correct++; }

        const currentAccuracy = val.length > 0 ? Math.round((correct / val.length) * 100) : 100;
        setAccuracy(currentAccuracy);

        const timeSpent = 60 - timeLeft;
        if (started && timeSpent > 0) {
            const currentWpm = Math.round((correct / 5) / (timeSpent / 60));
            setWpm(currentWpm);
        }

        if (val.length >= TEXT.length) finishTest(val);
    };

    const reset = () => {
        setInput(''); setStarted(false); setCompleted(false);
        setTimeLeft(60); setWpm(0); setAccuracy(100);
        setTimeout(() => inputRef.current?.focus(), 100);
    };

    const completionPercent = Math.round((input.length / TEXT.length) * 100);

    return (
        <div style={{ maxWidth: 1050, margin: '0 auto', fontFamily: 'var(--sans, sans-serif)', padding: '10px' }}>
            <style>{`
                .t-char { transition: color 0.1s; }
                .t-correct { color: #34d399; text-shadow: 0 0 10px rgba(52, 211, 153, 0.4); }
                .t-wrong { color: #ef4444; background: rgba(239, 68, 68, 0.2); border-radius: 2px; }
                .t-cursor { border-left: 2px solid #38bdf8; animation: blink 1s infinite; padding-left: 2px; }
                @keyframes blink { 50% { border-color: transparent; } }
            `}</style>

            <motion.div
                initial={{ opacity: 0, y: 30 }}
                animate={{ opacity: 1, y: 0 }}
                transition={{ duration: 0.5 }}
                className="typing-test-grid"
                style={{
                    gap: 24, alignItems: 'stretch'
                }}
            >
                <div style={{
                    padding: 32,
                    background: 'linear-gradient(160deg, rgba(15, 23, 42, 0.8) 0%, rgba(15, 23, 42, 0.95) 100%)',
                    backdropFilter: 'blur(20px)',
                    border: '1px solid rgba(139, 92, 246, 0.2)',
                    borderRadius: 24,
                    display: 'flex',
                    flexDirection: 'column',
                    boxShadow: '0 25px 50px -12px rgba(0, 0, 0, 0.5), inset 0 1px 0 rgba(255,255,255,0.1)'
                }}>
                    <div style={{ fontSize: '0.8rem', fontWeight: 800, color: '#8b5cf6', letterSpacing: '1.5px', textTransform: 'uppercase', marginBottom: 6 }}>
                        Freelancer Performance Tracker
                    </div>
                    <div style={{ fontSize: '1.4rem', fontWeight: 800, color: '#f8fafc', marginBottom: 8, lineHeight: 1.2 }}>
                        Prove your typing speed & accuracy <span style={{ color: '#94a3b8' }} className="font-normal">to unlock premium client tiers</span>
                    </div>

                    <div style={{ background: 'rgba(255,255,255,0.03)', border: '1px solid rgba(255,255,255,0.05)', padding: '12px 16px', borderRadius: 12, display: 'flex', alignItems: 'center', gap: 12, marginBottom: 32, marginTop: 12 }}>
                        <div style={{ background: 'rgba(139, 92, 246, 0.15)', padding: 8, borderRadius: 8, color: '#a78bfa' }}><Crosshair size={20} /></div>
                        <div>
                            <div style={{ fontSize: '0.9rem', fontWeight: 700, color: '#f8fafc' }}>Skill Verification</div>
                            <div style={{ fontSize: '0.75rem', color: '#94a3b8' }}>Type the text accurately to verify your skills</div>
                        </div>
                    </div>

                    <div className="typing-stats-grid" style={{ gap: 16, marginBottom: 16 }}>
                        <div style={{ background: 'rgba(255,255,255,0.02)', border: '1px solid rgba(255,255,255,0.05)', borderRadius: 16, padding: '20px 16px', textAlign: 'center' }}>
                            <div style={{ fontSize: '0.75rem', fontWeight: 700, color: '#94a3b8', textTransform: 'uppercase', letterSpacing: '0.5px', marginBottom: 8 }}>Time Left</div>
                            <div style={{ fontSize: '2.5rem', fontWeight: 800, color: timeLeft <= 10 ? '#ef4444' : '#38bdf8', fontFamily: 'var(--mono)', lineHeight: 1 }}>
                                {timeLeft}s
                            </div>
                        </div>

                        <div style={{ background: 'rgba(255,255,255,0.02)', border: '1px solid rgba(255,255,255,0.05)', borderRadius: 16, padding: '20px 16px', textAlign: 'center' }}>
                            <div style={{ fontSize: '0.75rem', fontWeight: 700, color: '#94a3b8', textTransform: 'uppercase', letterSpacing: '0.5px', marginBottom: 8 }}>Speed</div>
                            <div style={{ fontSize: '2.5rem', fontWeight: 800, color: '#f8fafc', fontFamily: 'var(--mono)', lineHeight: 1 }}>
                                {wpm} <span style={{ fontSize: '0.9rem', fontWeight: 600, color: '#64748b' }}>WPM</span>
                            </div>
                        </div>
                    </div>

                    <div className="typing-stats-grid" style={{ gap: 16, marginTop: 'auto' }}>
                        <div style={{ background: 'rgba(255,255,255,0.02)', border: '1px solid rgba(255,255,255,0.05)', borderRadius: 16, padding: '16px', display: 'flex', flexDirection: 'column', justifyContent: 'center' }}>
                            <div style={{ fontSize: '1.5rem', fontWeight: 800, color: accuracy < 95 ? '#f59e0b' : '#34d399', fontFamily: 'var(--mono)', lineHeight: 1, marginBottom: 4 }}>
                                {accuracy}%
                            </div>
                            <div style={{ fontSize: '0.75rem', fontWeight: 700, color: '#94a3b8', textTransform: 'uppercase', letterSpacing: '0.5px' }}>Accuracy</div>
                        </div>

                        <div style={{ background: 'rgba(255,255,255,0.02)', border: '1px solid rgba(255,255,255,0.05)', borderRadius: 16, padding: '16px', display: 'flex', flexDirection: 'column', justifyContent: 'center' }}>
                            <div style={{ fontSize: '1.25rem', fontWeight: 800, color: '#f8fafc', fontFamily: 'var(--mono)', lineHeight: 1, marginBottom: 4 }}>
                                {input.length} <span style={{ color: '#475569' }}>/ {TEXT.length}</span>
                            </div>
                            <div style={{ fontSize: '0.75rem', fontWeight: 700, color: '#94a3b8', textTransform: 'uppercase', letterSpacing: '0.5px' }}>Characters</div>
                        </div>
                    </div>

                </div>

                <div style={{
                    padding: 36,
                    background: 'rgba(15, 23, 42, 0.6)',
                    backdropFilter: 'blur(20px)',
                    border: '1px solid rgba(255,255,255,0.08)',
                    borderRadius: 24,
                    display: 'flex',
                    flexDirection: 'column',
                    boxShadow: '0 10px 30px -10px rgba(0, 0, 0, 0.5)',
                    position: 'relative',
                    cursor: completed ? 'default' : 'text'
                }} onClick={() => inputRef.current?.focus()}>

                    <div style={{
                        flex: 1,
                        fontSize: '1.4rem',
                        lineHeight: 1.8,
                        color: '#475569',
                        fontFamily: 'var(--mono)',
                        outline: 'none',
                        position: 'relative'
                    }}>
                        {!started && !completed && input.length === 0 && (
                            <motion.div
                                initial={{ opacity: 0 }}
                                animate={{ opacity: 1 }}
                                transition={{ repeat: Infinity, duration: 2, ease: "easeInOut" }}
                                style={{ position: 'absolute', top: -30, left: 0, color: '#38bdf8', fontSize: '0.85rem', fontWeight: 600, textTransform: 'uppercase', letterSpacing: '1px' }}
                            >
                                Start typing here to begin the test...
                            </motion.div>
                        )}

                        {TEXT.split('').map((char, i) => {
                            let cls = 't-char';
                            if (i < input.length) {
                                cls += input[i] === char ? ' t-correct' : ' t-wrong';
                            }
                            const isCursor = i === input.length && !completed;
                            return (
                                <span key={i} className={`${cls}${isCursor ? ' t-cursor' : ''}`}>
                                    {char}
                                </span>
                            );
                        })}
                    </div>

                    <textarea
                        ref={inputRef}
                        value={input}
                        onChange={handleChange}
                        disabled={completed}
                        autoComplete="off" spellCheck="false" autoCorrect="off" autoCapitalize="off"
                        style={{ position: 'absolute', inset: 0, opacity: 0, resize: 'none', background: 'transparent', color: 'transparent', border: 'none', outline: 'none', cursor: 'text', zIndex: 1 }}
                    />

                    <div style={{ marginTop: 40, borderTop: '1px solid rgba(255,255,255,0.05)', paddingTop: 24, display: 'flex', alignItems: 'center', justifyContent: 'space-between' }}>
                        <div style={{ display: 'flex', alignItems: 'center', gap: 16, flex: 1, paddingRight: 32 }}>
                            <div style={{ fontSize: '0.8rem', fontWeight: 800, color: '#38bdf8', width: 40 }}>{completionPercent}%</div>
                            <div style={{ height: 6, background: 'rgba(255,255,255,0.05)', borderRadius: 3, flex: 1, overflow: 'hidden' }}>
                                <div style={{ height: '100%', background: 'linear-gradient(90deg, #8b5cf6, #38bdf8)', width: `${completionPercent}%`, transition: 'width 0.2s', borderRadius: 3 }} />
                            </div>
                        </div>

                        <button
                            onClick={(e) => { e.stopPropagation(); reset(); }}
                            style={{
                                padding: '10px 20px', background: 'rgba(255,255,255,0.03)', color: '#e2e8f0',
                                border: '1px solid rgba(255,255,255,0.1)', borderRadius: 12, fontSize: '0.85rem', fontWeight: 600,
                                display: 'flex', alignItems: 'center', gap: 8, cursor: 'pointer', transition: 'all 0.2s'
                            }}
                            onMouseOver={e => { e.currentTarget.style.background = 'rgba(255,255,255,0.08)'; }}
                            onMouseOut={e => { e.currentTarget.style.background = 'rgba(255,255,255,0.03)'; }}
                        >
                            <RotateCcw size={16} /> Restart
                        </button>
                    </div>

                    {completed && (
                        <motion.div
                            initial={{ backdropFilter: 'blur(0px)', backgroundColor: 'rgba(15,23,42,0)' }}
                            animate={{ backdropFilter: 'blur(10px)', backgroundColor: 'rgba(15,23,42,0.85)' }}
                            style={{ position: 'absolute', inset: 0, borderRadius: 24, display: 'flex', flexDirection: 'column', alignItems: 'center', justifyContent: 'center', zIndex: 10 }}
                        >
                            <motion.div
                                initial={{ scale: 0.8, opacity: 0 }} animate={{ scale: 1, opacity: 1 }} transition={{ delay: 0.2, type: 'spring' }}
